<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{RefreshCw,Search}from'@lucide/vue';import{getOperatorUsage,listOperatorResource}from'@/api/operator';import type{OperatorCustomer,UsageReport}from'@/types';import{useI18n}from'vue-i18n';const{t}=useI18n();const report=ref<UsageReport|null>(null),customers=ref<OperatorCustomer[]>([]),customerID=ref(''),query=ref(''),loading=ref(false),error=ref('');const customerByID=computed(()=>Object.fromEntries(customers.value.map(v=>[v.id,v])));const money=(v=0)=>new Intl.NumberFormat(undefined,{style:'currency',currency:'USD',maximumFractionDigits:6}).format(v/1_000_000);async function load(){loading.value=true;try{[report.value,customers.value]=await Promise.all([getOperatorUsage({customer_id:customerID.value,q:query.value,limit:100}),listOperatorResource('customers') as Promise<OperatorCustomer[]>])}catch(e){error.value=e instanceof Error?e.message:t('common.failed')}finally{loading.value=false}}onMounted(load);</script><template><main class="content crud-page"><section class="page-header"><div><h1>{{t('operator.traffic')}}</h1><p>{{t('operator.trafficHelp')}}</p></div></section><div class="crud-summary"><span><strong>{{report?.total_requests||0}}</strong>{{t('usage.requests')}}</span><span><strong>{{report?.total_tokens||0}}</strong>{{t('usage.tokens')}}</span><span><strong>{{report?.error_requests||0}}</strong>{{t('usage.errors')}}</span><span><strong>{{money(report?.total_usage_cost_micros)}}</strong>{{t('usage.cost')}}</span></div><section class="table-toolbar"><label class="search-box"><Search :size="17"/><input v-model="query" :placeholder="t('operatorCrud.search')"/></label><select v-model="customerID"><option value="">{{t('operatorDomain.allCustomers')}}</option><option v-for="v in customers" :key="v.id" :value="v.id">{{v.name}}</option></select><button class="button secondary" :disabled="loading" @click="load"><RefreshCw :size="17"/>{{t('common.refresh')}}</button></section><div v-if="error" class="notice">{{error}}</div><section class="panel table-panel"><div class="panel-body table-scroll"><table class="data-table crud-table"><thead><tr><th>{{t('audit.time')}}</th><th>{{t('operatorDomain.customer')}}</th><th>{{t('usage.apiKey')}}</th><th>{{t('usage.model')}}</th><th>{{t('usage.route')}}</th><th>{{t('usage.tokens')}}</th><th>{{t('usage.cost')}}</th><th>{{t('providers.status')}}</th></tr></thead><tbody><tr v-for="v in report?.recent||[]" :key="v.id"><td>{{new Date(v.created_at).toLocaleString()}}</td><td>{{customerByID[v.customer_id]?.name||v.customer_id||'-'}}</td><td><strong>{{v.api_fingerprint}}</strong><span>{{v.api_key_id}}</span></td><td><strong>{{v.model}}</strong><span>{{v.upstream_model||'-'}}</span></td><td><strong>{{v.provider_id||'-'}}</strong><span>{{v.provider_account_id||'-'}}</span></td><td>{{v.input_tokens+v.output_tokens}}</td><td>{{money(v.usage_cost_micros)}}</td><td><span class="pill" :class="v.status==='forwarded'?'status-success':'status-warning'">{{v.status}}</span></td></tr><tr v-if="!(report?.recent||[]).length"><td colspan="8" class="empty-cell"></td></tr></tbody></table></div></section></main></template>
